function clean(t){return(t||'').replace(/\s+/g,' ').replace(/Explicit|Album|Song|Video/g,'').trim()}
function up(u){if(!u)return'';return u.replace(/=w[0-9]+-h[0-9]+.*$/i,'=w800-h800-l90-rj').replace(/\/s[0-9]+\//i,'/s800/')}
