document.addEventListener('play',function(e){if(e.target&&(e.target.tagName==='VIDEO'||e.target.tagName==='AUDIO'))markPlay()},true);document.addEventListener('pause',function(e){if(e.target&&(e.target.tagName==='VIDEO'||e.target.tagName==='AUDIO'))markPause()},true);['waiting','stalled','suspend','emptied','error','abort'].forEach(function(ev){document.addEventListener(ev,function(e){if(e.target&&(e.target.tagName==='VIDEO'||e.target.tagName==='AUDIO')){if(!window._kdUserPaused)window._kdShouldBePlaying=true}},true)});document.addEventListener('visibilitychange',function(){var x=m();if(x&&window._kdShouldBePlaying&&!window._kdUserPaused)play(x)},true);
setInterval(function(){try{var x=m();if(!x)return;var n=Date.now(),cur=x.currentTime||0,paused=x.paused,ended=x.ended,ready=x.readyState||0,net=x.networkState||0;if(!paused&&!ended){window._kdShouldBePlaying=true;window._kdUserPaused=false}var moved=Math.abs(cur-window._kdLastMediaTime)>.12,stuck=window._kdShouldBePlaying&&!window._kdUserPaused&&!ended&&!moved&&n-window._kdLastMediaCheck>2200,buf=window._kdShouldBePlaying&&!window._kdUserPaused&&!ended&&ready<3,fake=window._kdShouldBePlaying&&!window._kdUserPaused&&!ended&&(net===2||net===3||ready===0);if((stuck||buf||fake||paused)&&window._kdShouldBePlaying&&!window._kdUserPaused){window._kdRecovering=true;try{if(net===3||ready===0)x.load()}catch(e){}play(x);setTimeout(function(){window._kdRecovering=false},900)}window._kdLastMediaTime=cur;window._kdLastMediaCheck=n}catch(e){}},900)}
