val KORNDOG_SYNCED_LYRICS_SCRIPT="""
(function(){if(window._kdLyricsHighlightInit)return;window._kdLyricsHighlightInit=true;function css(){var o=document.getElementById('korndog-lyrics-highlight-style');if(o)o.remove();var s=document.createElement('style');s.id='korndog-lyrics-highlight-style';s.textContent=`ytmusic-description-shelf-renderer,ytmusic-description-shelf-renderer *,ytmusic-player-section-list-renderer,ytmusic-player-section-list-renderer *,ytmusic-player-page [role="tabpanel"],ytmusic-player-page [role="tabpanel"] *,.lyrics,.lyrics *,.lyrics-wrapper,.lyrics-wrapper *{color:#d8ffd0!important}.korndog-lyric-line{display:inline-block!important;color:#d8ffd0!important;transition:color .2s ease,text-shadow .2s ease,transform .2s ease!important}.korndog-lyric-active{color:#39ff14!important;font-weight:900!important;text-shadow:0 0 12px rgba(57,255,20,.95),0 0 24px rgba(57,255,20,.55)!important;transform:scale(1.025)!important}`;document.head.appendChild(s)}
css();setInterval(css,3000);function vis(e){if(!e)return false;var r=e.getBoundingClientRect();return r.width>0&&r.height>0}function box(){var ss=['ytmusic-description-shelf-renderer','ytmusic-player-section-list-renderer','ytmusic-player-page [role="tabpanel"]','.lyrics-wrapper','.lyrics'];for(var i=0;i<ss.length;i++){var ns=document.querySelectorAll(ss[i]);for(var j=0;j<ns.length;j++){var e=ns[j],t=(e.innerText||'').trim();if(vis(e)&&t.length>60)return e}}return null}function wrap(c){if(!c||c._kdLyricsWrapped)return;c._kdLyricsWrapped=true;var w=document.createTreeWalker(c,NodeFilter.SHOW_TEXT,null),nodes=[],n;while((n=w.nextNode())){var t=(n.textContent||'').trim();if(t.indexOf('Source:')===0||t.indexOf('Musixmatch')>-1||t.indexOf('LyricFind')>-1)return;if(t.length>2&&t.length<220&&n.parentElement&&vis(n.parentElement))nodes.push(n)}nodes.forEach(function(n,i){try{if(n.parentElement&&n.parentElement.classList.contains('korndog-lyric-line'))return;var s=document.createElement('span');s.className='korndog-lyric-line';s.setAttribute('data-korndog-lyric-index',String(i));n.parentNode.insertBefore(s,n);s.appendChild(n)}catch(e){}})}function hi(){var lines=Array.from(document.querySelectorAll('.korndog-lyric-line'));if(!lines.length)return;var y=window.innerHeight*.42,b=null,d=Infinity;lines.forEach(function(l){if(!vis(l))return;var r=l.getBoundingClientRect(),x=Math.abs(r.top-y);if(x<d){d=x;b=l}});lines.forEach(function(l){l.classList.remove('korndog-lyric-active')});if(b)b.classList.add('korndog-lyric-active')}setInterval(function(){try{var c=box();if(c){wrap(c);hi()}}catch(e){}},500);
