    webViewClient=object:WebViewClient(){override fun doUpdateVisitedHistory(v:WebView,u:String,isReload:Boolean){if(pageUrl!=u){pageUrl=u;onLoad(mapOf("url" to pageUrl))}};override fun onPageStarted(v:WebView,u:String,f:Bitmap?){evaluateJavascript(scriptOnStart,null)};override fun onPageFinished(v:WebView,u:String){evaluateJavascript(KORNDOG_CAST_SCRIPT,null);evaluateJavascript(KORNDOG_QUEUE_TRACKER_SCRIPT,null);evaluateJavascript(KORNDOG_SYNCED_LYRICS_SCRIPT,null)};override fun shouldInterceptRequest(v:WebView,r:WebResourceRequest):WebResourceResponse?=null;override fun shouldOverrideUrlLoading(v:WebView,u:String):Boolean{val uri=Uri.parse(u);return if(uri.host in VIEW_HOSTS||uri.host?.startsWith("accounts.google.")==true||uri.host?.startsWith("gds.google.")==true||uri.host?.endsWith(".youtube.com")==true)false else{v.context.startActivity(Intent(Intent.ACTION_VIEW,uri));true}}}
    webChromeClient=object:WebChromeClient(){override fun onPermissionRequest(r:PermissionRequest){val a=currentActivity;if(a==null){r.deny();return};val ps=mutableListOf<String>();if(r.resources.contains(PermissionRequest.RESOURCE_AUDIO_CAPTURE))ps.add(android.Manifest.permission.RECORD_AUDIO);if(r.resources.contains(PermissionRequest.RESOURCE_VIDEO_CAPTURE))ps.add(android.Manifest.permission.CAMERA);if(ps.isEmpty()){r.grant(r.resources);return};a.requestPermissions(ps.toTypedArray(),101);r.grant(r.resources)};override fun onJsBeforeUnload(v:WebView,u:String,m:String,res:JsResult):Boolean{res.confirm();return true};override fun onShowCustomView(v:View,cb:CustomViewCallback){customView=v;v.keepScreenOn=true;val a=currentActivity?:return;val w=a.window;(w.decorView as FrameLayout).addView(v,FrameLayout.LayoutParams(ViewGroup.LayoutParams.MATCH_PARENT,ViewGroup.LayoutParams.MATCH_PARENT));a.requestedOrientation=ActivityInfo.SCREEN_ORIENTATION_SENSOR_LANDSCAPE;val c=WindowCompat.getInsetsController(w,w.decorView);c.hide(WindowInsetsCompat.Type.systemBars());c.systemBarsBehavior=WindowInsetsControllerCompat.BEHAVIOR_SHOW_TRANSIENT_BARS_BY_SWIPE;if(Settings.System.getInt(a.contentResolver,Settings.System.ACCELEROMETER_ROTATION,0)==1)orientationListener.enable()};override fun onHideCustomView(){val a=currentActivity?:return;val w=a.window;(w.decorView as FrameLayout).removeView(customView);customView?.keepScreenOn=false;customView=null;a.requestedOrientation=ActivityInfo.SCREEN_ORIENTATION_USER;val c=WindowCompat.getInsetsController(w,w.decorView);c.show(WindowInsetsCompat.Type.systemBars());c.systemBarsBehavior=WindowInsetsControllerCompat.BEHAVIOR_DEFAULT;this@apply.requestFocus();orientationListener.disable()}}
  }
  init{addView(webView);initService();initWakeLock();currentActivity?.registerForContextMenu(webView);webView.addJavascriptInterface(NouJsInterface(context,this),"NouTubeI");ViewCompat.setOnApplyWindowInsetsListener(webView){_,_->WindowInsetsCompat.CONSUMED}}
